+async function loadConfigFiles(
+  options: ConfigOptions,
+): Promise<{ path?: string; values: ConfigValues }> {
+  const searchPaths = options.searchPaths?.length
+    ? options.searchPaths
+    : [getCurrentDirectory()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  const values: ConfigValues = {};
+  let path: string | undefined;
+
+  for (const searchPath of searchPaths) {
+    for (const format of formats) {
+      const candidate = resolve(searchPath, getConfigFileName(options.name, format));
+      const content = await readConfigFile(candidate);
+      if (typeof content === "undefined") {
+        continue;
+      }
+
+      const parsed = parseConfigFile(candidate, content, format, options.parser);
+      const flattened = flattenConfig(parsed);
+      path ??= candidate;
+
+      if (options.mergeConfigs) {
+        for (const [key, value] of Object.entries(flattened)) {
+          if (!(key in values)) {
+            values[key] = value;
+          }
+        }
+      } else {
+        return { path, values: flattened };
+      }
+    }
+  }
+
+  return { path, values };
+}
+
+function getConfigFileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function parseConfigFile(
+  path: string,
+  content: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): ConfigValues {
+  try {
+    const values = parser
+      ? parser(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!isPlainObject(values)) {
+      throw new Error("expected an object");
+    }
+    return values;
+  } catch (error) {
+    throw new ConfigParseError(
+      path,
+      error instanceof Error ? error.message : "invalid configuration",
+      { cause: error },
+    );
+  }
+}
+
+function parseRc(content: string): ConfigValues {
+  const values: ConfigValues = {};
+  for (const [index, line] of content.split(/\\r?\
/).entries()) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) {
+      continue;
+    }
+    const separator = trimmed.indexOf("=");
+    if (separator === -1) {
+      throw new Error(`invalid RC entry on line ${index + 1}`);
+    }
+    const key = trimmed.slice(0, separator).trim();
+    let value = trimmed.slice(separator + 1).trim();
+    if (!key) {
+      throw new Error(`missing key on line ${index + 1}`);
+    }
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error(`unterminated quoted value on line ${index + 1}`);
+      }
+      value = value.slice(1, -1);
+    }
+    values[normalizeConfigKey(key)] = coerceRcValue(value);
+  }
+  return values;
+}
+
+function coerceRcValue(value: string): string | boolean | number {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:e[-+]?\\d+)?$/i.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+function flattenConfig(
+  values: ConfigValues,
+  prefix = "",
+  result: ConfigValues = {},
+): ConfigValues {
+  for (const [key, value] of Object.entries(values)) {
+    const name = prefix ? `${prefix}.${normalizeConfigKey(key)}` : normalizeConfigKey(key);
+    if (isPlainObject(value)) {
+      flattenConfig(value, name, result);
+    } else {
+      result[name] = value;
+    }
+  }
+  return result;
+}
+
+function normalizeConfigKey(key: string): string {
+  return key.replace(/-([a-z])/g, (_, letter: string) => letter.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is ConfigValues {
+  return typeof value === "object" && value !== null &&
+    (Object.getPrototypeOf(value) === Object.prototype || Object.getPrototypeOf(value) === null);
+}
+
+function getCurrentDirectory(): string {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  if (Deno) return Deno.cwd();
+  if (process) return process.cwd();
+  throw new Error("unsupported runtime");
+}
+
+async function readConfigFile(path: string): Promise<string | undefined> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as any;
+  try {
+    if (Deno) {
+      return await Deno.readTextFile(path);
+    }
+    const { readFile } = await import("node:fs/promises");
+    return await readFile(path, "utf8");
+  } catch (error) {
+    if (error instanceof Error && ("code" in error) &&
+      ((error as { code?: string }).code === "ENOENT" ||
+        (error as { code?: string }).code === "ENOTDIR")) {
+      return undefined;
+    }
+    if (Deno && error instanceof Deno.errors.NotFound) {
+      return undefined;
+    }
+    throw error;
+  }
+}
