+import { assertEquals, assertInstanceOf, assertThrows } from "@std/assert";
+import { test } from "@cliffy/internal/testing/test";
+import {
+  Command,
+  ConfigParseError,
+  ConfigValidationError,
+} from "../../mod.ts";
+
+async function withConfig(
+  files: Record<string, string>,
+  callback: (directory: string) => Promise<void>,
+) {
+  const directory = await Deno.makeTempDir();
+  try {
+    await Promise.all(
+      Object.entries(files).map(([name, content]) =>
+        Deno.writeTextFile(`${directory}/${name}`, content)
+      ),
+    );
+    await callback(directory);
+  } finally {
+    await Deno.remove(directory, { recursive: true });
+  }
+}
+
+test("command: loads JSON config values and lets CLI values override them", async () => {
+  await withConfig({ "app.json": '{"dry-run":false,"port":0}' }, async (directory) => {
+    const command = new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [directory] })
+      .option("--dry-run", "Dry run.")
+      .option("--port <port:number>", "Port.");
+
+    const result = await command.parse(["--port", "8080"]);
+    assertEquals(result.options, { dryRun: false, port: 8080 });
+    assertEquals(command.getConfigValues(), { dryRun: false, port: 0 });
+    assertEquals(command.getConfigPath(), `${directory}/app.json`);
+  });
+});
+
+test("command: reads RC config, merges files, and ignores unknown keys", async () => {
+  await withConfig(
+    {
+      ".app.rc": '# comment\
name = "hello world"\
count=0\
unknown=true\
',
+      "app.json": '{"name":"ignored"}',
+    },
+    async (directory) => {
+      const command = new Command()
+        .throwErrors()
+        .config({ name: "app", searchPaths: [directory], formats: [".rc", ".json"] })
+        .option("--name <name:string>", "Name.")
+        .option("--count <count:number>", "Count.");
